import React, { useState, useMemo, useCallback, useEffect } from 'react';

import { useLocation } from 'react-router-dom';

import {

  Button,

  CatalogListShell,

  DateRangeFilter,

  ErpListHeaderFilters,

  addToast,

  loadErpListTableConfig,

  saveErpListTableConfig,

  useCatalogTableBusy,

  type DateRangeValue,

  type ErpListTableConfig,

  useViewMobileLayout,

} from '@linm-soft/common-components';

import { SearchInput } from '@linm-soft/common-components';

import { useAppDispatch } from '../../../store/hooks';

import { ktService } from '../../../services/kt/ktService';

import type { LedgerEntryDto } from '../../../services/kt/models';

import { createAccountSearchConfig } from '../../../components/search';

import { reportPageLabels } from '../../../constants/reportPageLabels';

import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';

import {

  patchReportFilterFieldError,

  scrollToFirstReportFilterField,

  validateRequiredTrimmed,

  type ReportFilterFieldRef,

} from '../../../utils/reportFilterValidation';

import erp from '../../../styles/erpPage.module.css';

import { LedgerReportGrid, ReportListToolbar } from '../../../components/report';

import { VoucherListTableConfigModal } from '../../../components/voucher-list/VoucherListTableConfigModal';

import {

  getSoCaiPageSession,

  reportPageSessionKey,

  saveSoCaiPageSession,

} from '../../../components/report/reportPageSessionCache';

import {

  getReportGridRowMenuHintMessage,

  reportGridRowHintDismissStorageKey,

} from '../../../utils/reportGridRowMenuHint';



const labels = reportPageLabels.soCai;

const TEST_ID = 'erp-so-cai';



type SoCaiFilterErrors = {

  accountCode?: string;

};



const SO_CAI_FILTER_FIELDS: readonly ReportFilterFieldRef[] = [

  { errorKey: 'accountCode', fieldSuffix: 'account' },

];



const SoCaiPage: React.FC = () => {

  const dispatch = useAppDispatch();

  const location = useLocation();

  const viewMobile = useViewMobileLayout();

  const rowMenuHintMessage = viewMobile ? labels.rowMenuHintTouch : labels.rowMenuHint;

  const sessionKey = reportPageSessionKey(location.pathname, location.search);

  const cached = getSoCaiPageSession(sessionKey);



  const [accountCode, setAccountCode] = useState(cached?.accountCode ?? '111');

  const [accountName, setAccountName] = useState(cached?.accountName ?? '');

  const [fromDate, setFromDate] = useState<string | undefined>(cached?.fromDate);

  const [toDate, setToDate] = useState<string | undefined>(cached?.toDate);

  const [items, setItems] = useState<LedgerEntryDto[]>(cached?.items ?? []);

  const [loading, setLoading] = useState(false);

  const [filterErrors, setFilterErrors] = useState<SoCaiFilterErrors>({});

  const [configOpen, setConfigOpen] = useState(false);

  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>

    loadErpListTableConfig(`${TEST_ID}-report-table-config`),

  );

  const { showTableLoading } = useCatalogTableBusy(loading);

  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);



  useEffect(() => {

    saveSoCaiPageSession(sessionKey, {

      accountCode,

      accountName,

      fromDate,

      toDate,

      items,

    });

  }, [sessionKey, accountCode, accountName, fromDate, toDate, items]);



  const validateFilters = useCallback((): SoCaiFilterErrors => {

    const errors: SoCaiFilterErrors = {};

    const accountError = validateRequiredTrimmed(accountCode, labels.accountRequired);

    if (accountError) errors.accountCode = accountError;

    return errors;

  }, [accountCode]);



  const handleLoad = useCallback(() => {

    const errors = validateFilters();

    if (Object.keys(errors).length > 0) {

      setFilterErrors(errors);

      scrollToFirstReportFilterField(TEST_ID, SO_CAI_FILTER_FIELDS, errors);

      dispatch(addToast({ message: labels.filterValidationSummary, type: 'warning' }));

      return;

    }

    setFilterErrors({});

    setLoading(true);

    ktService.getLedger({ accountCode, fromDate, toDate })

      .then(setItems)

      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, labels.loadError), type: 'error' })))

      .finally(() => setLoading(false));

  }, [accountCode, fromDate, toDate, dispatch, validateFilters, labels.filterValidationSummary]);



  const handleSaveTableConfig = (next: ErpListTableConfig) => {

    setTableConfig(next);

    saveErpListTableConfig(`${TEST_ID}-report-table-config`, next);

  };



  const hasData = items.length > 0;



  const filters = (

    <ErpListHeaderFilters testIdPrefix={TEST_ID}>

      <div className={`${erp.field} ${erp.searchInGrid}`} data-testid={`${TEST_ID}-field-account`}>

        <SearchInput

          config={accountSearchConfig}

          label={labels.fieldAccount}

          required

          error={filterErrors.accountCode}

          value={accountCode}

          primaryDisplay={accountCode}

          secondaryDisplay={accountName}

          onChange={a => {

            patchReportFilterFieldError(setFilterErrors, 'accountCode');

            setAccountCode(a.code);

            setAccountName(a.name);

          }}

          onClear={() => {

            patchReportFilterFieldError(setFilterErrors, 'accountCode');

            setAccountCode('');

            setAccountName('');

          }}

          showSecondaryInput={false}

          placeholder={labels.accountPlaceholder}

        />

      </div>

      <div className={erp.field} data-testid={`${TEST_ID}-field-dateRange`}>

        <DateRangeFilter

          label="Thời gian"

          fullWidth

          testId={`${TEST_ID}-date-range`}

          fromDate={fromDate}

          toDate={toDate}

          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); }}

        />

      </div>

      <Button

        variant="primary"

        onClick={handleLoad}

        loading={loading}

        data-testid={`${TEST_ID}-view-btn`}

      >

        {labels.view}

      </Button>

    </ErpListHeaderFilters>

  );



  return (

    <div className={`${erp.page} ${erp.catalogListPage}`} data-catalog-list-page data-testid={TEST_ID}>

      <div className={erp.pageHeader}>

        <div className={erp.titleBlock}>

          <h1 className={erp.title}><i className="fas fa-book-open" /> {labels.title}</h1>

        </div>

      </div>



      <ReportListToolbar

        testIdPrefix={TEST_ID}

        onRefresh={handleLoad}

        canChart={hasData}

        canPrint={hasData}

        chartLabel={labels.rowMenuChart}

        onChart={() => dispatch(addToast({ message: labels.chartComingSoon, type: 'info' }))}

        onPrint={() => window.print()}

        onEditConfig={() => setConfigOpen(true)}

      />



      <CatalogListShell

        testIdPrefix={TEST_ID}

        title={labels.listTitle}

        showTableLoading={showTableLoading}

        filters={filters}

      >

        {!showTableLoading && items.length === 0 ? (

          <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>

        ) : !showTableLoading ? (

          <LedgerReportGrid

            items={items}

            labels={labels}

            testIdPrefix={TEST_ID}

            exportAccountCode={accountCode}

            reportTitle={labels.title}

            onRefresh={handleLoad}

            tableConfig={tableConfig}

            getRowMenuHintMessage={getReportGridRowMenuHintMessage(rowMenuHintMessage)}

            rowMenuHintDismissStorageKey={reportGridRowHintDismissStorageKey(TEST_ID)}

          />

        ) : null}

      </CatalogListShell>



      <VoucherListTableConfigModal

        isOpen={configOpen}

        onClose={() => setConfigOpen(false)}

        testIdPrefix={TEST_ID}

        config={tableConfig}

        onSave={handleSaveTableConfig}

      />

    </div>

  );

};



export default SoCaiPage;


